{"type":"freeform","cover":{"titleText":"","subTitleText":"","presenterText":"","dateText":"","logos":[]},"section":{"sectionText":"","smallerSectionText":""},"freeform":{"content":[[{"type":"text","stretch":true,"fillArea":true,"textSize":1,"textBackground":"grey","placeholderInvisible":false,"useFigureAdditionalScale":false,"figureAdditionalScale":1,"span":3,"markdown":"At the national level, data completeness is very high, with most indicators consistently above 95%.

